#include<bits/stdc++.h>
using namespace std;
long long dp[21][2][2],a[21];
long long dfs(long long p,bool l2,bool l1,bool lim)
{
    if(p==-1)
    {
        return 1;
    }
    if(!lim&&dp[p][l2][l1]!=-1)
    {
        return dp[p][l2][l1];
    }
    long long tmp=(lim?a[p]:9);
    long long ans=0;
    for(long long i=0;i<=tmp;i++)
    {
        if(l1&&l2&&i==6)
        {
            continue;
        }
        ans+=dfs(p-1,l1,(i==6),(lim&&i==a[p]));
    }
    if(!lim)
    {
        dp[p][l2][l1]=ans;
    }
    return ans;
}
long long calc(long long x)
{
    long long p=0;
    while(x)
    {
        a[p++]=x%10;
        x/=10;
    }
    return dfs(p-1,0,0,1);
}
int main()
{
    memset(dp,-1,sizeof(dp));
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n;
        scanf("%lld",&n);
        long long l=665,r=9999999999;
        while(l<r)
        {
            long long mid=(l+r)/2;
            if(mid+1-calc(mid)>=n)
            {
                r=mid;
            }
            else
            {
                l=mid+1;   
            }
        }
        printf("%lld\n",l);
    }
    return 0;
}
